// This code is generated by AI, edited by humans

import { describe, it, before, after } from "node:test";
import assert from "node:assert/strict";
import { evaluateConstraints } from "../src/services/constraintEvaluator.js";

describe("Constraint Evaluator — Unit Tests", () => {
  // ── NumericLimitConstraint ──────────────────────────────────────
  describe("NumericLimitConstraint", () => {
    it("passes when value is within limit (lte)", async () => {
      const result = await evaluateConstraints(
        [{ type: "NumericLimitConstraint", field: "claimAmount", operator: "lte", value: 5000 }],
        { claimAmount: 3500 }
      );
      assert.equal(result.pass, true);
    });

    it("fails when value exceeds limit (lte)", async () => {
      const result = await evaluateConstraints(
        [{ type: "NumericLimitConstraint", field: "claimAmount", operator: "lte", value: 5000 }],
        { claimAmount: 7500 }
      );
      assert.equal(result.pass, false);
      assert.equal(result.error, "constraint_failed");
    });

    it("fails closed when field is missing", async () => {
      const result = await evaluateConstraints(
        [{ type: "NumericLimitConstraint", field: "claimAmount", operator: "lte", value: 5000 }],
        {}
      );
      assert.equal(result.pass, false);
      // Semantic resolver returns semantic_identifier_unknown when no mapping exists;
      // direct field lookup returns context_field_missing
      assert.ok(
        ["context_field_missing", "semantic_identifier_unknown"].includes(result.results[0].error),
        `Expected context_field_missing or semantic_identifier_unknown, got ${result.results[0].error}`
      );
    });

    it("handles local nested field paths", async () => {
      const result = await evaluateConstraints(
        [{ type: "NumericLimitConstraint", field: "local.claimAmount", operator: "lte", value: 5000 }],
        { local: { claimAmount: 4000 } }
      );
      assert.equal(result.pass, true);
    });

    it("resolves governed semantic identifiers through the mapping profile", async () => {
      const result = await evaluateConstraints(
        [{ type: "NumericLimitConstraint", field: "core.amount", operator: "lte", value: 5000 }],
        { claimAmount: 4000 }
      );
      assert.equal(result.pass, true);
    });
  });

  // ── EnumeratedListConstraint ────────────────────────────────────
  describe("EnumeratedListConstraint", () => {
    it("passes when value is in allowed list", async () => {
      const result = await evaluateConstraints(
        [{ type: "EnumeratedListConstraint", field: "claimType", allowed: ["rear_end", "collision"] }],
        { claimType: "rear_end" }
      );
      assert.equal(result.pass, true);
    });

    it("fails when value is not in allowed list", async () => {
      const result = await evaluateConstraints(
        [{ type: "EnumeratedListConstraint", field: "claimType", allowed: ["rear_end", "collision"] }],
        { claimType: "flood" }
      );
      assert.equal(result.pass, false);
    });

    it("deny takes precedence over allow", async () => {
      const result = await evaluateConstraints(
        [{ type: "EnumeratedListConstraint", field: "claimType", allowed: ["rear_end", "fraud"], denied: ["fraud"] }],
        { claimType: "fraud" }
      );
      assert.equal(result.pass, false);
    });
  });

  // ── StringPatternConstraint ─────────────────────────────────────
  describe("StringPatternConstraint", () => {
    it("matches exact", async () => {
      const result = await evaluateConstraints(
        [{ type: "StringPatternConstraint", field: "resource", pattern: "/claims/CLM-2026-0001", matchType: "exact" }],
        { resource: "/claims/CLM-2026-0001" }
      );
      assert.equal(result.pass, true);
    });

    it("matches prefix", async () => {
      const result = await evaluateConstraints(
        [{ type: "StringPatternConstraint", field: "resource", pattern: "/claims/CLM-2026-", matchType: "prefix" }],
        { resource: "/claims/CLM-2026-0042" }
      );
      assert.equal(result.pass, true);
    });

    it("fails prefix mismatch", async () => {
      const result = await evaluateConstraints(
        [{ type: "StringPatternConstraint", field: "resource", pattern: "/claims/CLM-2026-", matchType: "prefix" }],
        { resource: "/claims/CLM-2025-0042" }
      );
      assert.equal(result.pass, false);
    });

    it("matches restricted_glob", async () => {
      const result = await evaluateConstraints(
        [{ type: "StringPatternConstraint", field: "resource", pattern: "/claims/CLM-2026-*", matchType: "restricted_glob" }],
        { resource: "/claims/CLM-2026-9999" }
      );
      assert.equal(result.pass, true);
    });

    it("fails restricted_glob mismatch", async () => {
      const result = await evaluateConstraints(
        [{ type: "StringPatternConstraint", field: "resource", pattern: "/claims/CLM-2026-*", matchType: "restricted_glob" }],
        { resource: "/payments/PAY-2026-0001" }
      );
      assert.equal(result.pass, false);
    });
  });

  // ── TemporalWindowConstraint ────────────────────────────────────
  describe("TemporalWindowConstraint", () => {
    it("passes when within time window", async () => {
      // Use a timestamp we control — Wednesday 10:00 AM UTC
      const result = await evaluateConstraints(
        [{
          type: "TemporalWindowConstraint",
          field: "timestamp",
          validFrom: "08:00",
          validUntil: "18:00",
          timezone: "UTC",
          daysOfWeek: ["Mon", "Tue", "Wed", "Thu", "Fri"],
        }],
        { timestamp: "2026-04-15T10:00:00Z" } // Wednesday
      );
      assert.equal(result.pass, true);
    });

    it("fails when outside time window", async () => {
      const result = await evaluateConstraints(
        [{
          type: "TemporalWindowConstraint",
          field: "timestamp",
          validFrom: "08:00",
          validUntil: "18:00",
          timezone: "UTC",
          daysOfWeek: ["Mon", "Tue", "Wed", "Thu", "Fri"],
        }],
        { timestamp: "2026-04-15T20:00:00Z" } // Wednesday 8 PM
      );
      assert.equal(result.pass, false);
    });
  });

  // ── Unknown constraint type ─────────────────────────────────────
  describe("Fail-closed on unknown types", () => {
    it("fails closed on unknown constraint type", async () => {
      const result = await evaluateConstraints(
        [{ type: "GeofenceConstraint", field: "location" }],
        { location: "US" }
      );
      assert.equal(result.pass, false);
      assert.equal(result.results[0].error, "constraint_unknown");
    });
  });

  // ── AND logic ───────────────────────────────────────────────────
  describe("AND logic across multiple constraints", () => {
    it("requires all constraints to pass", async () => {
      const result = await evaluateConstraints(
        [
          { type: "NumericLimitConstraint", field: "claimAmount", operator: "lte", value: 5000 },
          { type: "EnumeratedListConstraint", field: "claimType", allowed: ["rear_end", "collision"] },
          { type: "StringPatternConstraint", field: "resource", pattern: "/claims/CLM-2026-", matchType: "prefix" },
        ],
        { claimAmount: 3500, claimType: "rear_end", resource: "/claims/CLM-2026-0042" }
      );
      assert.equal(result.pass, true);
      assert.equal(result.results.length, 3);
    });

    it("fails if any one constraint fails", async () => {
      const result = await evaluateConstraints(
        [
          { type: "NumericLimitConstraint", field: "claimAmount", operator: "lte", value: 5000 },
          { type: "EnumeratedListConstraint", field: "claimType", allowed: ["rear_end"] },
        ],
        { claimAmount: 3500, claimType: "flood" }
      );
      assert.equal(result.pass, false);
    });
  });
});
